INSERT INTO ai_prompts (display_name, prompt_template, category, is_active) VALUES
('Tôi nên học gì để làm lập trình viên?', 'Tôi muốn trở thành lập trình viên. Bạn có thể tư vấn lộ trình học tập và các kỹ năng cần thiết không?', 'career', TRUE),
('Mức lương lập trình viên tại Việt Nam?', 'Mức lương trung bình của lập trình viên các cấp độ (fresher, junior, mid, senior) tại Việt Nam hiện nay là bao nhiêu?', 'career', TRUE),
('Làm thế nào để tìm việc nhanh hơn?', 'Tôi đang tìm việc làm nhưng chưa có kết quả. Bạn có thể cho tôi một số lời khuyên để tăng cơ hội tìm việc không?', 'career', TRUE),
('Tôi phù hợp với nghề gì?', 'Dựa vào hồ sơ và kỹ năng của tôi, bạn có thể gợi ý những ngành nghề phù hợp với tôi không?', 'career', TRUE),
('Phân tích CV của tôi', 'Hãy phân tích CV của tôi và cho biết điểm mạnh, điểm yếu và cách cải thiện để tăng cơ hội được phỏng vấn.', 'resume', TRUE),
('CV của tôi có phù hợp với vị trí này không?', 'Hãy đánh giá xem CV của tôi có phù hợp với vị trí tôi đang ứng tuyển không và tôi cần bổ sung gì.', 'resume', TRUE),
('Câu hỏi phỏng vấn thường gặp', 'Những câu hỏi phỏng vấn thường gặp nhất cho vị trí tôi đang ứng tuyển là gì? Và cách trả lời hiệu quả?', 'interview', TRUE),
('Làm sao để vượt qua vòng phỏng vấn?', 'Bạn có thể chia sẻ các mẹo và chiến lược để tôi tự tin hơn và thành công trong buổi phỏng vấn sắp tới?', 'interview', TRUE),
('Tôi nên mặc gì khi đi phỏng vấn?', 'Trang phục phù hợp cho buổi phỏng vấn xin việc trong lĩnh vực công nghệ/văn phòng là gì?', 'interview', TRUE),
('Lộ trình thăng tiến của tôi', 'Dựa vào vị trí hiện tại và kinh nghiệm của tôi, lộ trình thăng tiến phù hợp trong 3-5 năm tới là gì?', 'orientation', TRUE),
('Xu hướng ngành CNTT năm 2026', 'Những xu hướng công nghệ nào đang hot nhất trong ngành CNTT năm 2026 và tôi nên học gì để không bị lạc hậu?', 'orientation', TRUE),
('Chuyển ngành có khó không?', 'Tôi đang làm việc trong ngành khác và muốn chuyển sang CNTT. Bạn có thể tư vấn cho tôi lộ trình và những thách thức cần vượt qua?', 'orientation', TRUE);
